// Tenant slug sent by the dashboard
const tenantSlug = $('Webhook').first().json.body?.tenant_slug || '';

// All Google Sheet rows as plain objects
const rows = $input.all().map(i => i.json);

// Filter by tenant_slug column if present
const filtered = rows.filter(row => {
  if (!tenantSlug) return true;
  const slug = (row['tenant_slug'] || row['Tenant Slug'] || row['tenant'] || '').toLowerCase();
  return !slug || slug === tenantSlug.toLowerCase();
});

// Normalise column names (handle spaces vs underscores)
const result = filtered.slice(-200).reverse().map(row => ({
  call_id:          row['call_id']          || row['Call ID']          || row['id']               || '',
  phone_number:     row['phone_number']      || row['Phone Number']     || row['phone']            || '—',
  direction:        row['direction']         || row['Direction']        || 'inbound',
  status:           row['status']            || row['Status']           || row['end_reason']       || '—',
  duration_seconds: parseInt(row['duration_seconds'] || row['Duration (s)'] || row['duration'] || 0),
  summary:          row['summary']           || row['Summary']          || row['transcript_summary'] || '',
  created_at:       row['created_at']        || row['Started At']       || row['timestamp']        || row['Date'] || '',
  ended_at:         row['ended_at']          || row['Ended At']         || '',
  tenant_slug:      row['tenant_slug']       || row['Tenant Slug']      || tenantSlug
}));

return [{ json: { result } }];
